+"use client";
+
+/**
+ * ShareDialog - Modal for creating and managing share links
+ *
+ * Features:
+ * - Generate shareable links for prompts, packs, and skills
+ * - Optional password protection
+ * - Configurable expiration
+ * - Social sharing options (Twitter, LinkedIn)
+ * - Copy to clipboard functionality
+ */
+
+import { useState, useCallback } from "react";
+import {
+  Copy,
+  Check,
+  Link2,
+  Lock,
+  Unlock,
+  Clock,
+  Eye,
+  Trash2,
+  Twitter,
+  Linkedin,
+  Globe,
+  Share2,
+} from "lucide-react";
+import {
+  Dialog,
+  DialogContent,
+  DialogHeader,
+  DialogTitle,
+  DialogDescription,
+  DialogBody,
+  DialogFooter,
+} from "@/components/ui/dialog";
+import { Button } from "@/components/ui/button";
+import { Input } from "@/components/ui/input";
+import { Switch } from "@/components/ui/switch";
+import { Label } from "@/components/ui/label";
+import {
+  Select,
+  SelectContent,
+  SelectItem,
+  SelectTrigger,
+  SelectValue,
+} from "@/components/ui/select";
+import { useToast } from "@/components/ui/toast";
+import { cn } from "@/lib/utils";
+import { trackEvent } from "@/lib/analytics";
+
+// Types
+export type ShareableContentType = "prompt" | "pack" | "skill" | "collection";
+
+export interface ShareLink {
+  linkCode: string;
+  url: string;
+  password: string | null;
+  expiresAt: string | null;
+  viewCount: number;
+  createdAt: string;
+}
+
+export interface ShareDialogProps {
+  open: boolean;
+  onOpenChange: (open: boolean) => void;
+  contentType: ShareableContentType;
+  contentId: string;
+  contentTitle: string;
+  /** Existing share link if one already exists */
+  existingShare?: ShareLink | null;
+  /** Whether the content is currently public (in Swap Meet) */
+  isPublic?: boolean;
+  /** Callback when a new share link is created */
+  onShareCreated?: (share: ShareLink) => void;
+  /** Callback when share link is revoked */
+  onShareRevoked?: () => void;
+  /** Callback when visibility is toggled */
+  onVisibilityChange?: (isPublic: boolean) => void;
+}
+
+const EXPIRATION_OPTIONS = [
+  { value: "never", label: "Never expires" },
+  { value: "7", label: "7 days" },
+  { value: "30", label: "30 days" },
+  { value: "90", label: "90 days" },
+];
+
+function generateMockLinkCode(): string {
+  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789";
+  return Array.from(
+    { length: 12 },
+    () => chars[Math.floor(Math.random() * chars.length)]
+  ).join("");
+}
+
+export function ShareDialog({
+  open,
+  onOpenChange,
+  contentType,
+  contentId,
+  contentTitle,
+  existingShare,
+  isPublic = false,
+  onShareCreated,
+  onShareRevoked,
+  onVisibilityChange,
+}: ShareDialogProps) {
+  const { success, error: toastError } = useToast();
+  const [copied, setCopied] = useState(false);
+  const [isCreating, setIsCreating] = useState(false);
+  const [isRevoking, setIsRevoking] = useState(false);
+
+  // Form state
+  const [passwordEnabled, setPasswordEnabled] = useState(
+    !!existingShare?.password
+  );
+  const [password, setPassword] = useState("");
+  const [expiration, setExpiration] = useState<string>(
+    existingShare?.expiresAt ? "custom" : "never"
+  );
+
+  // Derived state
+  const shareUrl = existingShare?.url || null;
+  const hasExistingShare = !!existingShare;
+
+  const handleCopyLink = useCallback(async () => {
+    if (!shareUrl) return;
+
+    try {
+      await navigator.clipboard.writeText(shareUrl);
+      setCopied(true);
+      if ("vibrate" in navigator) navigator.vibrate(50);
+      success("Link copied", "Share link copied to clipboard", 3000);
+      trackEvent("share_link_copy", { contentType, contentId });
+      setTimeout(() => setCopied(false), 2000);
+    } catch {
+      toastError("Failed to copy", "Please try again");
+    }
+  }, [shareUrl, contentType, contentId, success, toastError]);
+
+  const handleCreateShare = useCallback(async () => {
+    setIsCreating(true);
+    try {
+      // Mock API call - will be replaced with real API
+      await new Promise((resolve) => setTimeout(resolve, 500));
+
+      const mockShare: ShareLink = {
+        linkCode: generateMockLinkCode(),
+        url: `https://jeffreysprompts.com/share/${generateMockLinkCode()}`,
+        password: passwordEnabled ? password : null,
+        expiresAt:
+          expiration !== "never"
+            ? new Date(
+                Date.now() + parseInt(expiration) * 24 * 60 * 60 * 1000
+              ).toISOString()
+            : null,
+        viewCount: 0,
+        createdAt: new Date().toISOString(),
+      };
+
+      onShareCreated?.(mockShare);
+      success("Share link created", "Your content is now shareable", 3000);
+      trackEvent("share_link_create", { contentType, contentId });
+    } catch {
+      toastError("Failed to create share link", "Please try again");
+    } finally {
+      setIsCreating(false);
+    }
+  }, [
+    contentType,
+    contentId,
+    passwordEnabled,
+    password,
+    expiration,
+    onShareCreated,
+    success,
+    toastError,
+  ]);
+
+  const handleRevokeShare = useCallback(async () => {
+    setIsRevoking(true);
